#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        int robots[N];
        for (int i = 0; i < N; i++) {
            robots[i] = i + 1;
        }
        // Move the first M robots to the end of the row
        int temp[M];
        for (int i = 0; i < M; i++) {
            temp[i] = robots[i];
        }
        for (int i = M; i < N; i++) {
            robots[i - M] = robots[i];
        }
        for (int i = 0; i < M; i++) {
            robots[N - M + i] = temp[i];
        }
        // Distribute cakes to the robots
        int cakes[N];
        for (int i = 0; i < N; i++) {
            cakes[i] = 0;
        }
        int current = 0;
        cakes[current] = 1;
        while (true) {
            int next = robots[current] - 1;
            if (cakes[next] == 1) {
                break;
            }
            cakes[next] = 1;
            current = next;
        }
        // Count the number of robots with cakes
        int count = 0;
        for (int i = 0; i < N; i++) {
            if (cakes[i] == 1) {
                count++;
            }
        }
        if (count == N) {
            printf("Yes\n");
        } else {
            printf("No %d\n", count);
        }
    }
    return 0;
}

