const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
let T = parseInt(lines[idx++]);
while (T-- > 0) {
    let [N, M] = lines[idx++].trim().split(' ').map(Number);
    let robots = Array.from({ length: N }, (_, i) => i + 1);
    // Move the first M robots to the end of the row
    let temp = robots.slice(0, M);
    robots = robots.slice(M).concat(temp);
    // Distribute cakes to the robots
    let cakes = new Array(N).fill(0);
    let current = 0;
    cakes[current] = 1;
    while (true) {
        let next = robots[current] - 1;
        if (cakes[next] === 1) {
            break;
        }
        cakes[next] = 1;
        current = next;
    }
    // Count the number of robots with cakes
    let count = cakes.filter(cake => cake === 1).length;
    if (count === N) {
        console.log('Yes');
    } else {
        console.log(`No ${count}`);
    }
}
